<script lang="ts">
  const html: string = "<h1>Menu Group</h1>\n\n<p>A menu group is a labeled section of menu items within a menu. It groups related actions and presents a visible heading that names the group.</p>\n\n<p>Use it inside a <code>Menu</code>, <code>DropdownMenu</code>, or <code>ContextMenu</code> to organize items into clear sections — for example, \"File\", \"Edit\", or \"View\" — making longer menus easier to scan.</p>\n\n<h2>Implementation Notes</h2>\n\n<ul>\n<li>Uses a <code>&lt;div&gt;</code> with <code>role=\"group\"</code> and a required <code>aria-label</code></li>\n<li>Renders a visible heading element <code>&lt;div class=\"menu-group-heading\" aria-hidden=\"true\"&gt;</code> containing the label text</li>\n<li>The heading is hidden from assistive technology because the <code>aria-label</code> already conveys the group name to AT</li>\n<li>Children are typically <code>MenuItem</code> components</li>\n</ul>\n\n<h2>Props</h2>\n\n<ul>\n<li><code>label</code>: string (<strong>required</strong>) -- section heading text (also used as aria-label)</li>\n<li><code>children</code>: slot -- <code>menu-item</code> children</li>\n<li><code>...restProps</code>: any additional HTML attributes</li>\n</ul>\n\n<h2>Usage</h2>\n\n<pre><code class=\"language-html\">&lt;Menu label=\"File menu\"&gt;\n  &lt;MenuGroup label=\"File\"&gt;\n    &lt;MenuItem&gt;New&lt;/MenuItem&gt;\n    &lt;MenuItem&gt;Open&lt;/MenuItem&gt;\n    &lt;MenuItem&gt;Save&lt;/MenuItem&gt;\n  &lt;/MenuGroup&gt;\n  &lt;MenuGroup label=\"Edit\"&gt;\n    &lt;MenuItem&gt;Undo&lt;/MenuItem&gt;\n    &lt;MenuItem&gt;Redo&lt;/MenuItem&gt;\n  &lt;/MenuGroup&gt;\n&lt;/Menu&gt;</code></pre>\n\n<h2>Keyboard Interactions</h2>\n\n<ul>\n<li>(Provided by the parent menu) Arrow keys: Move focus between menu items, including across group boundaries</li>\n<li>(Provided by the parent menu) Enter / Space: Activate the focused menu item</li>\n<li>(Provided by the parent menu) Escape: Close the menu</li>\n</ul>\n\n<h2>ARIA</h2>\n\n<ul>\n<li><code>role=\"group\"</code> on the container</li>\n<li><code>aria-label</code> provides the accessible name (required)</li>\n<li>The visible heading uses <code>aria-hidden=\"true\"</code> to avoid double-announcement</li>\n</ul>\n\n<h2>When to Use</h2>\n\n<ul>\n<li>Use to divide a menu into clearly labeled sections</li>\n<li>Use when item categories help users scan and find actions</li>\n<li>Use within a parent <code>Menu</code>, <code>DropdownMenu</code>, or <code>ContextMenu</code></li>\n</ul>\n\n<h2>When Not to Use</h2>\n\n<ul>\n<li>Do not use for unrelated, ungrouped menu items</li>\n<li>Do not nest groups inside groups — flatten the structure or use a submenu</li>\n<li>Do not use as a standalone menu — pair with a parent menu</li>\n</ul>\n\n<h2>Composition</h2>\n\n<p>Menu groups sit inside a parent menu and contain <code>MenuItem</code> children:</p>\n\n<pre><code class=\"language-html\">&lt;Menu label=\"Actions\"&gt;\n  &lt;MenuGroup label=\"Recent files\"&gt;\n    &lt;MenuItem&gt;report.pdf&lt;/MenuItem&gt;\n    &lt;MenuItem&gt;notes.md&lt;/MenuItem&gt;\n  &lt;/MenuGroup&gt;\n&lt;/Menu&gt;</code></pre>\n\n<h2>Headless</h2>\n\n<p>Renders a <code>&lt;div role=\"group\"&gt;</code> with <code>aria-label</code> plus a hidden-from-AT heading and slotted <code>MenuItem</code> children. Spacing, dividers, and visual treatment are entirely the consumer's responsibility.</p>\n\n<h2>Styles</h2>\n\n<p>Consumer CSS targets the <code>menu-group</code> class and the inner <code>menu-group-heading</code> class for the visible label. Provide visual separation between groups (e.g., a top border or extra padding) without relying on color alone.</p>\n\n<h2>Testing</h2>\n\n<ul>\n<li>Verify the component renders a <code>&lt;div&gt;</code> with <code>role=\"group\"</code> and class <code>menu-group</code></li>\n<li>Verify <code>aria-label</code> equals the <code>label</code> prop</li>\n<li>Verify the visible heading is rendered with class <code>menu-group-heading</code> and <code>aria-hidden=\"true\"</code></li>\n<li>Verify the heading text equals the <code>label</code> prop</li>\n<li>Verify children are rendered after the heading</li>\n</ul>\n\n<h2>Advice</h2>\n\n<ul>\n<li><strong>Designers</strong>: Use group labels that describe the category, not the count or layout (e.g., \"Edit\", not \"Three options\").</li>\n<li><strong>Developers</strong>: Localize the <code>label</code> prop; avoid translating it inside the component.</li>\n</ul>\n\n<h2>Related components</h2>\n\n<ul>\n<li><code>menu-item</code> — one item in a menu</li>\n</ul>\n\n<h2>References</h2>\n\n<ul>\n<li>WAI-ARIA Menu Pattern: https://www.w3.org/WAI/ARIA/apg/patterns/menubar/</li>\n<li>WAI-ARIA Group: https://www.w3.org/TR/wai-aria-1.2/#group</li>\n<li>Adobe Spectrum Menu: https://spectrum.adobe.com/page/menu/</li>\n</ul>";
  // BEGIN auto-generated component example consts
  const demoHtml: string = "<div class=\"menu-group\" aria-label=\"a labeled section of menu items within a menu\">MenuGroup</div>";
  const svelteSource: string = "// In your Svelte component:\nimport MenuGroup from \"lily-design-system-svelte-headless/components/MenuGroup/MenuGroup.svelte\";\n\n<MenuGroup>\n  <!-- list children -->\n</MenuGroup>\n";
  // END auto-generated component example consts
</script>

